sequence.script:
function value(name, fallback) {
    var current = mc.getProperty(name);
    return current == null || String(current).length === 0
        ? fallback
        : String(current);
}

mc.setPayloadJSON({
    service: value('adapter.name', 'unknown'),
    status: 'UNAVAILABLE',
    error: {
        code: value('ERROR_CODE', value('adapter.error.code', 'DOWNSTREAM_UNAVAILABLE')),
        message: value('ERROR_MESSAGE', value('adapter.error.message', 'Downstream service unavailable')),
        detail: value('ERROR_DETAIL', 'The integration continued according to the partial-response policy.')
    },
    correlationId: value('correlation.id', '')
});
